# ARM / Bicep: assign a role at resource group scope (deployed at RG level)
targetScope = 'resourceGroup'

param principalId string
param roleDefinitionId string = 'b24988ac-6180-42a0-ab88-20f7382dd24c'  // Contributor

resource roleAssignment 'Microsoft.Authorization/roleAssignments@2022-04-01' = {
  name: guid(resourceGroup().id, principalId, roleDefinitionId)
  properties: {
    roleDefinitionId: subscriptionResourceId('Microsoft.Authorization/roleDefinitions', roleDefinitionId)
    principalId: principalId
    principalType: 'ServicePrincipal'
  }
}

# Bicep: assign at subscription scope
targetScope = 'subscription'

resource subRoleAssignment 'Microsoft.Authorization/roleAssignments@2022-04-01' = {
  name: guid(subscription().id, principalId, roleDefinitionId)
  properties: {
    roleDefinitionId: tenantResourceId('Microsoft.Authorization/roleDefinitions', roleDefinitionId)
    principalId: principalId
    principalType: 'Group'
  }
}

# Terraform: role assignment at specific resource scope
# resource "azurerm_role_assignment" "kv_secrets_user" {
#   scope                = azurerm_key_vault.prod.id
#   role_definition_name = "Key Vault Secrets User"
#   principal_id         = azurerm_user_assigned_identity.app.principal_id
# }

# Terraform: role assignment at management group scope
# resource "azurerm_role_assignment" "security_reader_mg" {
#   scope                = "/providers/Microsoft.Management/managementGroups/${var.root_mg_id}"
#   role_definition_name = "Security Reader"
#   principal_id         = azuread_group.security_team.object_id
# }

# Audit: find all Owner assignments across all subscriptions
$ownerRoleId = '8e3af657-a8ff-443c-a75c-2fe8c4bcb635'
$subs = Get-AzSubscription
foreach ($sub in $subs) {
    Set-AzContext -SubscriptionId $sub.Id | Out-Null
    Get-AzRoleAssignment -RoleDefinitionId $ownerRoleId |
        Select-Object @{N='Subscription';E={$sub.Name}}, DisplayName, ObjectType, Scope
} | Format-Table

# Report: count role assignments per scope level
Get-AzRoleAssignment | ForEach-Object {
    $parts = $_.Scope.Split('/')
    $level = switch ($parts.Count) {
        2 { 'Root/MG' }
        3 { 'Subscription' }
        5 { 'ResourceGroup' }
        default { 'Resource' }
    }
    [PSCustomObject]@{ Scope = $level; Role = $_.RoleDefinitionName; Principal = $_.DisplayName }
} | Group-Object Scope | Select-Object Name, Count

# Find assignments with scope broader than resource group (subscription or MG)
Get-AzRoleAssignment | Where-Object {
    $parts = $_.Scope.TrimStart('/').Split('/')
    $parts.Count -le 2  # subscription = 2 segments; MG = 4 segments with /providers/...
} | Select-Object DisplayName, RoleDefinitionName, Scope | Format-Table
